    """Select a tip key from TIPS, optionally biased by self.tip_weights.

    If self.tip_weights is None, falls back to a uniform draw via
    self.rng.choice(). Otherwise, weights are normalized into a
    cumulative distribution and self.rng.random() is used to pick a
    key. Nonpositive or missing weights are treated as 0.0; if all
    weights end up zero/invalid, falls back to a uniform draw.
    """
    tip_keys = list(TIPS.keys())

    if self.tip_weights is None:
        return self.rng.choice(tip_keys)

    weights = [max(self.tip_weights.get(key, 1.0), 0.0) for key in tip_keys]
    total_weight = sum(weights)

    if total_weight <= 0:
